449	fn verify_ptx_only() -> Result<(), Box<dyn std::error::Error>> {
450	    let ptx_path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tcgen05.ptx");
451	
452	    if !ptx_path.exists() {
453	        return Err("PTX file not found".into());
454	    }
455	
456	    println!("\n📝 PTX Verification:");
457	    println!("   PTX file generated at: {}", ptx_path.display());
458	
459	    let ptxas_result = std::process::Command::new("ptxas")
460	        .arg("-arch=sm_120a")
461	        .arg(&ptx_path)
462	        .arg("-o")
463	        .arg("/dev/null")
464	        .output();
465	
466	    match ptxas_result {
467	        Ok(output) if output.status.success() => {
468	            println!("   ✓ PTX validated by ptxas (sm_120a)");
469	        }
470	        Ok(output) => {
471	            println!("   ⚠️  ptxas validation failed:");
472	            println!("      {}", String::from_utf8_lossy(&output.stderr));
473	        }
474	        Err(_) => {
475	            println!("   ℹ️  ptxas not found - cannot validate PTX");
476	        }
477	    }
478	
479	    println!("\n📝 To inspect generated PTX:");
480	    println!("   cat {}", ptx_path.display());
481	    println!("\n   Look for: tcgen05.fence, tcgen05.alloc, tcgen05.mma.ws instructions");
482	
483	    Ok(())
484	}
