20	/// Convert `nvvm.movmatrix_trans_b16` to inline PTX.
21	///
22	/// `movmatrix.sync.aligned.m8n8.trans.b16 $0, $1;`
23	///
24	/// Warp-synchronous, uses convergent inline assembly.
25	pub(crate) fn convert_movmatrix_trans_b16(
26	    ctx: &mut Context,
27	    rewriter: &mut DialectConversionRewriter,
28	    op: Ptr<Operation>,
29	    _operands_info: &OperandsInfo,
30	) -> Result<()> {
31	    let operands: Vec<_> = op.deref(ctx).operands().collect();
32	    if operands.len() != 1 {
33	        return pliron::input_err_noloc!(
34	            "movmatrix_trans_b16 requires 1 operand, got {}",
35	            operands.len()
36	        );
37	    }
38	
39	    let a_val = operands[0];
40	
41	    let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
42	
43	    let inline_asm = llvm::InlineAsmOp::build(
44	        ctx,
45	        i32_ty.into(),
46	        vec![a_val],
47	        "movmatrix.sync.aligned.m8n8.trans.b16 $0, $1;",
48	        "=r,r",
49	        AsmKind::Convergent,
50	    );
51	
52	    let asm_op = inline_asm.get_operation();
53	    rewriter.insert_operation(ctx, asm_op);
54	    rewriter.replace_operation(ctx, op, asm_op);
55	    Ok(())
56	}
