60	/// Operand order is C[0..4], A[0..4], B[0..2]. The four D registers are
61	/// returned as an LLVM struct and then split back into the dialect op's four
62	/// SSA results. There are no hidden pointer, stack, load, or store operands.
63	pub(crate) fn convert_mma_m16n8k16_f32_bf16(
64	    ctx: &mut Context,
65	    rewriter: &mut DialectConversionRewriter,
66	    op: Ptr<Operation>,
67	    _operands_info: &OperandsInfo,
